var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제 2 난민지구 침식지대\\n<color=#ffd34c>비정규 수색 분대</color> 정기소탕 의뢰 수행 중\\nCSE Level 2+","JPN":"第2難民地区侵食地帯\\n<color=#ffd34c>非正規捜索分隊</color>定期掃討依頼遂行中\\nCSE Level 2+","ENG":"[[","TWN":"第2難民區侵蝕地區\\n<color=#ffd34c>非正式搜查分隊</color>執行定期掃蕩委託中\\nCSE Level 2+","THA":"บริเวณที่ถูกคอร์รัปต์  เขตผู้ลี้ภัยที่สอง\\n<color=#ffd34c>ทีมค้นหาไม่ปกติ</color> ในภารกิจปราบปรามปกติ\\nCSE เลเวล 2+","VTN":"Khu Vực Bị Ăn Mòn, Khu tị nạn thứ 2\\n<color=#ffd34c>Đội kiểm soát không định kỳ </color> chấp hành nhiệm vụ tiêu diệt thông thường\\nCSE Cấp 2+","SCN":"第二难民区侵蚀地区\\n<color=#ffd34c>非正规搜查分队</color>定期清剿委托执行中\\nCSE Level 2+","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"다들 들어 봐. 바깥이 잠잠해졌어.","JPN":"おい、待て。外が静かになったぞ。","ENG":"Guys, listen. I don't hear anything outside anymore.","TWN":"你們聽，外面沒聲音了。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"침식체 놈들, 포기하고 가 버린 거 아냐?","JPN":"侵食体のやつら、諦めて帰ったんじゃないか？","ENG":"The C.O.s must have given up and left.","TWN":"侵蝕體是不是放棄走掉啦？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"히익……!","JPN":"ひいっ……！","ENG":"Heek...!","TWN":"嗚嗚……！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"반대편 벽에 바짝 붙어 있으세요. 그러다 다 같이 죽을 수도 있어요.","JPN":"反対側の壁に固まっててください。下手したら皆ここで死ぬかもしれません。","ENG":"Stay close to the opposite wall, or we could all die together.","TWN":"請貼緊對面牆壁，否則大家很可能會一起死！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그럼 여기 계속 있자는 뜻이야? 우리가 이 비좁은 데 갇힌 지 얼마나 지났는데?","JPN":"ずっとここで待機しろと？　この狭い場所にに閉じ込められてどれだけ経つと思ってんだ？","ENG":"Are you saying we should stay here? Don't you know how long we've been cooped up in this tiny place?","TWN":"意思是叫我們繼續待在這裡嗎？我們被困在這個狹小的空間裡都多久了？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"조금만 더 참아요. 정기 연락이 끊긴 지 오래됐으니까 곧 지원을 보내 줄 거예요.","JPN":"もう少し我慢してください。ずっと定期連絡ができてないから、向こうも気づいてすぐ支援を送ってくれるはずです。","ENG":"Let's be patient a little longer. We've missed quite a few regular reports. Help will be here soon.","TWN":"請再忍耐一下，我們這麼長時間沒有回報消息，他們一定很會就會派支援來的！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"지원을 보내?","JPN":"支援を送る？","ENG":"Help?","TWN":"派支援來？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"누가? 우리 같은 떨거지들도 겨우 고용한 저 가난뱅이들이?","JPN":"誰が？　俺たちみたいな連中を辛うじて雇えたぐらいの、あの金ないやつらがか？","ENG":"From whom? Those paupers who can barely afford third-rate mercenaries like us?","TWN":"誰派？那些只請得起我們這種傭兵的窮鬼嗎？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"의뢰주라고 불러요. 앞으로도 용병 일 계속 하고 싶으면.","JPN":"依頼主、です。これからも傭兵やっていきたいなら、言葉には気をつけてください。","ENG":"You'd better call them clients if you want to stay in business.","TWN":"請稱呼他們為委託人，如果你還想繼續當傭兵的話。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"안 해! 아니, 못 하겠지! 여기서 죽을 텐데!","JPN":"しねえよ！　いや、できねえだろうな！　どうせここで死ぬんだし！","ENG":"No, I'm not gonna! I probably couldn't do it even if I wanted to. Because I'm going to die here!","TWN":"不當了啦！不，是當不了！我都要死在這裡了！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"통신기는 어때요? 고칠 수 없겠어요?","JPN":"通信機の様子は？　直せそうですか？","ENG":"How's the radio? Can you fix it?","TWN":"通訊器怎麼樣？修不好嗎？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SHOTGUN_SL_NULL_NULL","text":{"KOREA":"글렀어. 부품이라도 하늘에서 뚝 떨어지면 모를까.","JPN":"駄目だ。空から部品が降りてこない限りは。","ENG":"No, unless it rains replacement parts.","TWN":"沒辦法，除是有天外突然飛來的零件吧？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHOTGUN_SL_NULL_NULL","text":{"KOREA":"구조 신호는 계속 보내고 있지만, 이 강도로는 침식지대 밖까지 닿지 않을 거야.","JPN":"救助信号は送り続けてるけど、この程度じゃ侵食地帯の外にまでは届かないだろうな。","ENG":"I've been sending distress signals, but I doubt they're strong enough to make it outside the Corrupted Area.","TWN":"雖然一直有在發求救訊號，但依照這個強度，可能無法傳達到侵蝕地區之外的地方。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"작전 중이던 다른 용병들이 신호를 받고 오길 바라야겠네요.","JPN":"作戦中の他の傭兵たちが信号に気づいて、ここに来てくれることを祈るしかありませんね。","ENG":"Then, let's hope other mercs in the area detect our signals and come to our rescue.","TWN":"現在只能期待作戰中的其他傭兵，能收到訊號來救我們。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"왜, 아예 관리국 연합함대가 온다고 하지 그래?","JPN":"ハッ、せっかくだから管理局の連合艦隊でも待ってたらどうだ？","ENG":"Just wait for the Administration coalition fleet, why don't you?","TWN":"是怎樣？你怎麼不乾脆說管理局聯合艦隊會來救我們？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"이딴 돈도 안 될 데를 들쑤시고 다니는 멍청이들은 우리뿐이라고! 당신네 세상은 그렇게 희망차?!","JPN":"そもそも金にもならねえこんな場所に来てるやつらなんて、俺たちぐらいしかいねえんだし、希望なんて持てるかよ！","ENG":"Get real. We're the only ones stupid enough to come to places like this that have no booty whatsoever.","TWN":"像這種鳥不生蛋的地方，只有我們這種蠢蛋會來！你們的世界還真是充滿希望呢？！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};